1	import { runScenario } from "./claim-office.js";
2	
3	// Pure transformation: scenario JSON in → results JSON out. Isolated from
4	// stdin/stdout plumbing so upcoming CLI validation tests (unknown item
5	// types, claim referencing absent policy item, negative amounts, etc.)
6	// can design error paths against this function directly without spawning
7	// a subprocess.
8	function scenarioJsonToResultJson(scenarioJson: string): string {
9	  const scenario = JSON.parse(scenarioJson);
10	  const result = runScenario(scenario);
11	  return JSON.stringify(result);
12	}
13	
14	function readAllStdin(): Promise<string> {
15	  return new Promise((resolve) => {
16	    let input = "";
17	    process.stdin.setEncoding("utf8");
18	    process.stdin.on("data", (chunk) => {
19	      input += chunk;
20	    });
21	    process.stdin.on("end", () => {
22	      resolve(input);
23	    });
24	  });
25	}
26	
27	async function main(): Promise<void> {
28	  const scenarioJson = await readAllStdin();
29	  process.stdout.write(scenarioJsonToResultJson(scenarioJson));
30	  process.exit(0);
31	}
32	
33	main();
